import React, { useEffect, useRef, useState } from 'react';
import { useTranslation } from 'react-i18next';
import { createChart, CandlestickSeries } from 'lightweight-charts';
import { getMT5Candles, getMT5Tick, getMT5Account } from '../services/api';
import TradingPanel from '../components/TradingPanel';
import './GoldChart.css';

function GoldChart() {
  const { t } = useTranslation();
  const chartContainerRef = useRef();
  const chartRef = useRef();
  const candlestickSeriesRef = useRef();
  const [timeframe, setTimeframe] = useState('H1');
  const [currentTick, setCurrentTick] = useState(null);
  const [accountInfo, setAccountInfo] = useState(null);

  const timeframes = ['M1', 'M5', 'M15', 'M30', 'H1', 'H4', 'D1'];

  useEffect(() => {
    // Create chart
    const chart = createChart(chartContainerRef.current, {
      layout: {
        background: { type: 'solid', color: '#16213e' },
        textColor: '#ddd',
      },
      grid: {
        vertLines: { color: '#333' },
        horzLines: { color: '#333' },
      },
      timeScale: {
        timeVisible: true,
        secondsVisible: false,
      },
    });

    chartRef.current = chart;

    const candlestickSeries = chart.addSeries(CandlestickSeries, {
      upColor: '#4ecdc4',
      downColor: '#ff6b6b',
      borderUpColor: '#4ecdc4',
      borderDownColor: '#ff6b6b',
      wickUpColor: '#4ecdc4',
      wickDownColor: '#ff6b6b',
    });

    candlestickSeriesRef.current = candlestickSeries;

    return () => {
      chart.remove();
    };
  }, []);

  useEffect(() => {
    const fetchCandles = async () => {
      try {
        const candles = await getMT5Candles('XAUUSD', timeframe, 500);
        const formattedData = candles.map(c => ({
          time: c.time,
          open: c.open,
          high: c.high,
          low: c.low,
          close: c.close,
        }));
        candlestickSeriesRef.current?.setData(formattedData);
      } catch (error) {
        console.error('Failed to fetch candles:', error);
      }
    };

    fetchCandles();
    const interval = setInterval(fetchCandles, 10000);
    return () => clearInterval(interval);
  }, [timeframe]);

  useEffect(() => {
    const fetchData = async () => {
      try {
        const tick = await getMT5Tick('XAUUSD');
        setCurrentTick(tick);

        const account = await getMT5Account();
        setAccountInfo(account);
      } catch (error) {
        console.error('Failed to fetch data:', error);
      }
    };

    fetchData();
    const interval = setInterval(fetchData, 1000);
    return () => clearInterval(interval);
  }, []);

  return (
    <div className="gold-chart">
      <div className="chart-header">
        <h1>{t('goldChart.title')}</h1>
        <div className="timeframe-selector">
          {timeframes.map(tf => (
            <button
              key={tf}
              className={`timeframe-btn ${timeframe === tf ? 'active' : ''}`}
              onClick={() => setTimeframe(tf)}
            >
              {t('goldChart.timeframes.' + tf) || tf}
            </button>
          ))}
        </div>
      </div>
      
      <div className="chart-container">
        <div className="chart-main">
          <div ref={chartContainerRef} className="chart-element" />
        </div>
        <div className="chart-sidebar">
          <TradingPanel 
            currentTick={currentTick} 
            accountInfo={accountInfo}
            onTradeSuccess={() => {}}
          />
        </div>
      </div>
    </div>
  );
}

export default GoldChart;
